from azure.identity import DefaultAzureCredential
from azure.mgmt.resource import ResourceManagementClient

credential = DefaultAzureCredential()
client = ResourceManagementClient(credential, "<subscription-id>")

REQUIRED_TAGS = {"environment": "dev", "cost-center": "engineering"}
resource_group = "rg-devtest-team-alpha"
resources_updated = 0

for resource in client.resources.list_by_resource_group(resource_group):
    existing_tags = resource.tags or {}
    missing = {k: v for k, v in REQUIRED_TAGS.items() if k not in existing_tags}
    if missing:
        merged = {**existing_tags, **missing}
        client.resources.begin_update_by_id(
            resource.id,
            resource.api_version or "2021-04-01",
            {"tags": merged},
        ).result()
        resources_updated += 1
        print(f"Tagged: {resource.name} with {missing}")

print(f"Updated tags on {resources_updated} resources.")
